package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.Reader;
import java.util.Arrays;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a dummy JsonElement for constructor (using JsonNull)
    reader = new JsonTreeReader(com.google.gson.JsonNull.INSTANCE);
  }

  @Test
  public void testPromoteNameToValue_success() throws Exception {
    // Arrange
    // Mock an Iterator<Map.Entry<?, ?>> with one entry
    @SuppressWarnings("unchecked")
    Iterator<Map.Entry<?, ?>> mockIterator = mock(Iterator.class);
    @SuppressWarnings("unchecked")
    Map.Entry<String, String> mockEntry = mock(Map.Entry.class);

    when(mockEntry.getKey()).thenReturn("mockKey");
    when(mockEntry.getValue()).thenReturn(new JsonPrimitive("mockValue"));
    when(mockIterator.next()).thenReturn(mockEntry);

    // Use reflection to set the private stack field with the mockIterator at top
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(reader);
    stack[0] = mockIterator;

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    // Spy on reader to mock expect(JsonToken.NAME) so it does not throw
    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.NAME);

    // Act
    Method promoteNameToValue = JsonTreeReader.class.getDeclaredMethod("promoteNameToValue");
    promoteNameToValue.setAccessible(true);
    promoteNameToValue.invoke(spyReader);

    // Assert
    // After promoteNameToValue, the stack size should be 3:
    // original iterator at bottom, then pushed value, then pushed key as JsonPrimitive
    int stackSizeAfter = stackSizeField.getInt(spyReader);
    assertEquals(3, stackSizeAfter);

    Object[] stackAfter = (Object[]) stackField.get(spyReader);

    // Top of stack is JsonPrimitive with key string
    Object top = stackAfter[stackSizeAfter - 1];
    assertTrue(top instanceof JsonPrimitive);
    assertEquals("mockKey", ((JsonPrimitive) top).getAsString());

    // Next element is the value from the entry
    Object second = stackAfter[stackSizeAfter - 2];
    assertTrue(second instanceof JsonPrimitive);
    assertEquals("mockValue", ((JsonPrimitive) second).getAsString());

    // The iterator remains at bottom
    assertSame(mockIterator, stackAfter[0]);

    // Verify that next() was called on the iterator
    verify(mockIterator).next();
  }

  @Test
  public void testPromoteNameToValue_expectThrows() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doThrow(new IOException("Expected token not found")).when(spyReader).expect(JsonToken.NAME);

    Method promoteNameToValue = JsonTreeReader.class.getDeclaredMethod("promoteNameToValue");
    promoteNameToValue.setAccessible(true);

    IOException thrown = assertThrows(IOException.class, () -> promoteNameToValue.invoke(spyReader));
    assertTrue(thrown.getCause().getMessage().contains("Expected token not found"));
  }
}
